INSERT INTO `sys_oper_log` VALUES (369, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":5,\"content\":\"<p>美食汉堡</p>\",\"createTime\":\"2025-03-02 21:23:58\",\"img\":\"/profile/upload/2025/03/02/核潜艇导弹_20250302235642A005.jpeg\",\"newsId\":5,\"params\":{},\"remark\":\"测试111\",\"status\":0,\"title\":\"测试默认审核状态：为0[添加时隐藏审核状态]\",\"updateTime\":\"2025-03-02 23:56:44\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-03-02 23:56:44', 9);
INSERT INTO `sys_oper_log` VALUES (370, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":1,\"content\":\"<p><strong>核潜艇的重要性</strong></p><p>核潜艇一直是核大国必备的“玩具”，只有拥有了它，才算凑齐了三位一体的核打击能力，这是必不可少的一环。然而，我国在这方面却一直饱受诟病，我们这一款装备的能力，长期以来都被认为要弱于美西方国家。而我们费尽千辛万苦才搞出来的第一代，曾经一度是美军口中的“笑话”，他们嘲讽我们的核潜艇噪音太大，就算隔着太平洋都能听见。等到094诞生以后，又因为它头顶的“龟背”，一度也成为不少人的嘲讽对象，而它至今仍是我国不可或缺的主力。但是一旦096诞生，那么情况很可能就不一样了，它如果出现，不仅很有希望追上一流的美俄，甚至有可能会超越他们！</p><p><img src=\\\"/dev-api/profile/upload/2025/02/20/核潜艇_20250220233516A001.png\\\"></p><p><strong>美俄的核潜艇水平</strong></p><p>我国在核潜艇这一方面，起步是很晚的，但不可否认的是，我们的进步却是非常快的。到现在而言，真正拥有战略级核潜艇的国家，也只有5个而已，而这五个国家，就是联合国的五常了。其中在这方面属于顶尖水平的，则是美俄两国了。</p><p>首先是美国的俄亥俄级，它早在上世纪80年代就入役了，技术可以说是非常成熟。它可以下潜到400米的深海中，执行任务的时间可以维持70天，航速也有25节，可以搭载24枚潜射导弹，最远可以打11000多千米。而且它的噪音控制也非常优秀，只有95分贝，在嘈杂的大洋环境之中，堪称“深海幽灵”，美国则有足足18艘这样的核潜艇。</p><p>而俄罗斯的北风之神级，在某些方面，要比美国的还要强大。首先就是它的航速，在水下可以达到26节。虽然它装载的弹道导弹数量只有16颗，但每一颗的威力都非常强大，射程可达14800多公里，而且每一颗导弹能携带10枚核弹头，每一枚核弹头爆炸的威力都相当于10万吨TNT，整艘潜艇如果满配，可以携带160枚这样的核弹头。换句话说，仅仅是一艘潜艇出动，就足以对一个国家进行毁灭性的打击。不过，它的降噪性能比美国稍差，水下噪音在108分贝，但出一次任务可以持续90天以上，这一项又超过了美国。</p><p>总结来说，美国的优势在隐身上，而俄罗斯的优势在火力上。</p><p><strong>我国现役核潜艇的水平</strong></p><p>我们现役的094和美俄的核潜艇相比，的确还有一些差距。094潜航的正常水平在300米，这一项在美俄之后；远洋作战自持力则在70天以上，和美国持平，但落后于俄罗斯；降噪水平上也存在缺陷，噪音控制能够降到110分贝，但和美国的95分贝相比，还是有不小差距，就连俄罗斯的108分贝我们也稍显不足。在武力方面，094装备的巨浪-2可以打7400千米，虽然也能够得着美国本土，但想要把它送到纽约，就必须通过关岛，这对于我们来说是非常危险的。可以说在方方面面，我们的094都有不足。</p><p><img src=\\\"/dev-api/profile/upload/2025/02/20/核潜艇导弹_20250220233538A002.jpeg\\\"></p><p><strong>096的突破与展望</strong></p><p>096和它的前辈094相比，可以说是有翻天覆地的变化。在096上，我们将使用全新的四项技术，重点放在改进噪音问题和射程问题上。其中，无轴泵推、全电推动、一体化自循环核反应堆这三项技术，是为了解决噪音的。无轴泵推直接拿掉螺旋桨的传动轴，实现电磁推动，避免了传动轴产生的巨大噪音；一体化自循环核反应堆技术则消除冷却泵发出的噪音；全电推动代替传统齿轮结构，进一步降低噪音。有了这三项技术，096的降噪性能将会有极大的提升，美国军方甚至预测096的水平很可能会超越北风之神，和他们的水平不相上下。</p><p>除了降噪，我们还将进一步提升096的下潜能力。现役的094使用的是10米左右的耐压壳，而2015年我们在耐压壳技术上取得了突破，已经可以达到13.5米的水准，这也就从侧面说明096的性能将比094更为恐怖。</p><p>更重要的是，我们在导弹射程方面也取得了很大进步。094搭载的是巨浪-2，而096预计将配备威力更大、射程更远的巨浪-3，其射程直接提高到12000公里以外。这意味着096只需待在安全海域，就能直接覆盖美国的东西海岸，误差小于100米。</p><p>此外，096还将配备全新的声呐阵和量子通信系统，使其追踪能力和抗干扰能力进一步增强，这和美国的传统卫星导航相比，优势明显。</p><p>可以说，新的096一旦出现，将会让美俄引以为傲的核潜艇荣光不再。这样全方位的提升，将让我们的核潜艇一跃成为', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-03-03 00:02:57', 10);
