INSERT INTO `sys_oper_log` VALUES (594, '评论', 2, 'com.newsrec.manage.controller.CommentsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/comments', '127.0.0.1', '内网IP', '{\"commentId\":1,\"content\":\"<p>毛神认为中国的核潜艇是全世界最厉害的</p>\",\"createTime\":\"2025-02-21 14:55:01\",\"newsId\":1,\"params\":{},\"parentId\":0,\"remark\":\"测试111\",\"updateTime\":\"2025-03-24 21:49:27\",\"userId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-03-24 21:49:27', 15);
