INSERT INTO `sys_oper_log` VALUES (619, '新闻内容', 1, 'com.newsrec.manage.controller.NewsController.add()', 'POST', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":8,\"content\":\"<p>混合双打速度快SHFLKSNFJKNKmWNDSAKNL.CN IWDJ\\t舒服舒服水电费多福多寿放大说法是多少递四方速递发放干哈撒额下达发达VVC发瓜娃儿违法的更大更啊都发给</p>\",\"createTime\":\"2025-04-01 09:58:35\",\"img\":\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/01/67eb482ad14181298a8c3b63.jpeg\",\"newsId\":29,\"params\":{},\"status\":0,\"title\":\"这是一条国际新闻\",\"userId\":2}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-01 09:58:35', 26);
