INSERT INTO `sys_oper_log` VALUES (653, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":1,\"content\":\"<p style=\\\"text-align: left;\\\">中印两军边境交手5年后，印度军方日前终于解密，在过去几年中，印方不仅在一线的交锋中落于下风，而且还在其他方面，承受了远超外界想象的惨痛损失。</p><p style=\\\"text-align: left;\\\">虽然印度这边不愿承认，但事实已经证明，与中国持续对峙的代价过大，就是莫迪政府在边境问题上主动作出调整的原因之一。</p><p style=\\\"text-align: left;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/70955039e1984f0d8a7592848c732d49~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744090546&amp;x-signature=MaaN7WQLdXjp6bb9J5SbkjExWhY%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p style=\\\"text-align: center;\\\">【现身中印边境西段的解放军装甲部队】</p><p style=\\\"text-align: left;\\\">印度国防部日前向该国议会报告，在2020年到2024年这5年时间里，印度国防部下属的边境道路组织 （BRO）在边境基建行动中死伤惨重，共有704名BRO人员与575名“临时工”死亡。</p><p style=\\\"text-align: left;\\\">这里说的BRO，是负责印度官方边境基础设施建设的关键部门。早在莫迪政府上台，印度放弃原本的“坚壁清野”政策，转而采取强化一线部署的威慑战略后，BRO就在加强中印边境的边境基建。在2020年中印边境冲突爆发后，推动中印边境方向的各类基建，提升印军兵力投递和物资保障能力更是成为BRO的头等大事。</p><p style=\\\"text-align: left;\\\">在此次报告中，印度国防部也重点介绍了他们在中印边境基建中取得的成绩，强调在过去5年中，他们完成了包括色拉隧道在内的诸多设施建设。</p><p style=\\\"text-align: left;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/a5479cf72a1f4e22bbf1b903fb79f477~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744090546&amp;x-signature=122kaehdMhwBk%2FpQgSvMQ54IEr4%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p style=\\\"text-align: center;\\\">【印度国防部称过去5年损失1200多人】</p><p style=\\\"text-align: left;\\\">因此，BRO这4年中损失的1279人，绝大部分是死在了中印边境方向的基建行动之中。死亡原因包括边境高原地带施工中的各类自然灾害、施工事故、疾病等。BRO也承认，在这5年时间里，BRO参与项目共发生了201起事故。</p><p style=\\\"text-align: left;\\\">印度国防部宣称，BRO为施工者们提供了足够的医疗保障，以及安全的工作条件，但5年死亡1200多人，平均不到2天就会有1名施工者身亡，足以说明印度在施工安全、边境地区医疗保障等领域的短板，而这背后反映出的是印度整体较弱的基建实力。</p><p style=\\\"text-align: left;\\\">此外，印方数据显示，在这5年中，BRO人员损失最惨重的是2021年，共死亡306人，比2020年多死了近40人。这足以说明，2020年中印边境局势恶化，中印军队在边境展开对峙，导致印方在军事压力之下，更加急切地推动边境基建，放大了印方的短板。</p><p style=\\\"text-align: left;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/fe6c178d344449c1a5cb5057138c04bf~tplv-tt-origin-', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-01 13:37:55', 19);
