INSERT INTO `sys_oper_log` VALUES (660, '通知公告', 2, 'com.newsrec.web.controller.system.SysNoticeController.edit()', 'PUT', 1, 'admin', '研发部门', '/system/notice', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2025-04-01 12:20:26\",\"noticeContent\":\"<p>轮播图根据当天的热榜新闻，每12小时自动刷新。</p><p>获取当前热榜前五条新闻信息，并进行首页推送，同时会定时清除轮播图。</p><p>同时后台管理员可以手动更新，一键及时更新，或者手动一个个添加定制轮播图。</p>\",\"noticeId\":12,\"noticeTitle\":\"系统更新：轮播图自动更新\",\"noticeType\":\"1\",\"params\":{},\"status\":\"0\",\"updateBy\":\"admin\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-01 14:24:05', 5);
