INSERT INTO `sys_oper_log` VALUES (672, '用户', 2, 'com.newsrec.manage.controller.UsersController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/users', '127.0.0.1', '内网IP', '{\"avatar\":\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/01/67eba7bdd14149d55ed67b98.jpg\",\"createTime\":\"2025-04-01 11:00:49\",\"email\":\"1978255928@qq.com\",\"params\":{},\"phone\":\"18861913525\",\"remark\":\"每天认真学习，调整自己，一定会成功的~\",\"updateTime\":\"2025-04-07 21:03:03\",\"userId\":11,\"username\":\"weiyan\"}', NULL, 1, '\r\n### Error updating database.  Cause: java.sql.SQLIntegrityConstraintViolationException: Duplicate entry \'18861913525\' for key \'tb_users.phone\'\r\n### The error may exist in file [Z:\\Projects\\Admin Panel\\newsrec\\newsrec-manage\\target\\classes\\mapper\\manage\\UsersMapper.xml]\r\n### The error may involve com.newsrec.manage.mapper.UsersMapper.updateUsers-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update tb_users          SET username = ?,             password = ?,             email = ?,             phone = ?,             avatar = ?,             remark = ?,             create_time = ?,             update_time = ?          where user_id = ?\r\n### Cause: java.sql.SQLIntegrityConstraintViolationException: Duplicate entry \'18861913525\' for key \'tb_users.phone\'\n; Duplicate entry \'18861913525\' for key \'tb_users.phone\'; nested exception is java.sql.SQLIntegrityConstraintViolationException: Duplicate entry \'18861913525\' for key \'tb_users.phone\'', '2025-04-07 21:03:03', 5);
