INSERT INTO `sys_oper_log` VALUES (675, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":5,\"content\":\"<p style=\\\"text-align: justify;\\\"><strong>近日，蔡徐坤名誉权案胜诉的消息引发广泛关注，给这场持续已久的舆论风波画上了句号</strong>。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p26-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/af61e6fbb0af44cbb0068f779dfb7a38~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744636121&amp;x-signature=XNaOXb2Otr3vn1HdpHX33%2BqaGW0%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>此前，微博账号“超能摄影阳阳”“懂瓜呱”等人在网络上公然捏造不实信息，对蔡徐坤发表诽谤性言论，给蔡徐坤的个人形象和声誉造成极大损害</strong>。<u>这些谣言在网络上迅速传播，误导公众认知，让蔡徐坤深陷舆论漩涡，承受着巨大的精神压力和名誉损失</u>。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/b5a0a43f52e246eaad19f462e49c415e~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744636121&amp;x-signature=mDYWVmKKcnodS2aD4vT4mXftxzM%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>面对恶意造谣，蔡徐坤没有选择沉默，而是勇敢地拿起法律武器捍卫自己的合法权益</strong>。<u>经过漫长的司法程序，法院最终判决蔡徐坤胜诉。这一胜利不仅是对他个人名誉的有力捍卫，更是对网络谣言的一次沉重打击</u>。胜诉意味着法律对造谣者的行为作出了明确的否定性评价，让他们为自己的违法行为承担应有的责任。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/4a1c5da176e84614ad453af2b3669ed7~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744636121&amp;x-signature=jHYNs23k0H59xQ9qPq4%2FG1j0z0s%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>蔡徐坤工作室随后表示，后续将持续关注并坚决追究任何侵犯蔡徐坤合法权益的主体及个人的法律责任，绝不姑息</strong>。<u>这彰显了蔡徐坤及其团队维护自身权益的坚定决心，也向社会传递出一个强烈信号</u>。网络并非法外之地，任何造谣、诽谤他人的行为都将受到法律的制裁。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p26-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/2ef3da5c5be44c1ea01b820c9d8a8305~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744636121&amp;x-signature=Vm9nPcpo1infz9c', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-07 21:11:15', 9);
INSERT INTO `sys_oper_log` VALUES (676, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":5,\"content\":\"<p style=\\\"text-align: justify;\\\"><strong>近日，蔡徐坤名誉权案胜诉的消息引发广泛关注，给这场持续已久的舆论风波画上了句号</strong>。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p26-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/af61e6fbb0af44cbb0068f779dfb7a38~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744636121&amp;x-signature=XNaOXb2Otr3vn1HdpHX33%2BqaGW0%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"width: 533.60px;height: 300.15px;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>此前，微博账号“超能摄影阳阳”“懂瓜呱”等人在网络上公然捏造不实信息，对蔡徐坤发表诽谤性言论，给蔡徐坤的个人形象和声誉造成极大损害</strong>。<u>这些谣言在网络上迅速传播，误导公众认知，让蔡徐坤深陷舆论漩涡，承受着巨大的精神压力和名誉损失</u>。</p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>面对恶意造谣，蔡徐坤没有选择沉默，而是勇敢地拿起法律武器捍卫自己的合法权益</strong>。<u>经过漫长的司法程序，法院最终判决蔡徐坤胜诉。这一胜利不仅是对他个人名誉的有力捍卫，更是对网络谣言的一次沉重打击</u>。胜诉意味着法律对造谣者的行为作出了明确的否定性评价，让他们为自己的违法行为承担应有的责任。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/07/67f3d029d14177fe6cf91adb.png\\\" alt=\\\"111.png\\\" data-href=\\\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/07/67f3d029d14177fe6cf91adb.png\\\" style=\\\"width: 506.60px;height: 506.60px;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>蔡徐坤工作室随后表示，后续将持续关注并坚决追究任何侵犯蔡徐坤合法权益的主体及个人的法律责任，绝不姑息</strong>。<u>这彰显了蔡徐坤及其团队维护自身权益的坚定决心，也向社会传递出一个强烈信号</u>。网络并非法外之地，任何造谣、诽谤他人的行为都将受到法律的制裁。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p26-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/2ef3da5c5be44c1ea01b820c9d8a8305~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744636121&amp;x-signature=Vm9nPcpo1infz9cems9AlKV1IaY%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"width: 540.60px;height: 304.09px;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>更值得称赞的是，蔡徐坤将本次胜诉获得的相关赔偿款通过公益项目捐出</strong>。这种做法不仅展现出他的善良与担当，也让这笔赔偿款有了更积极的社会意义。他用实际行动诠释了正能量，将负面事件转化为推动社会公益事业发展的力量 ，让伤害变成了温暖与希望的传递。</p>\",\"createBy\":\"weiyan\",\"createTime\":\"2025-04-07 21:10', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-07 21:21:32', 8);
INSERT INTO `sys_oper_log` VALUES (677, '轮播图', 3, 'com.newsrec.manage.controller.BannerController.remove()', 'DELETE', 1, 'admin', '研发部门', '/manage/banner/121,120,119,118,117', '127.0.0.1', '内网IP', '[121,120,119,118,117]', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-07 21:21:49', 5);
INSERT INTO `sys_oper_log` VALUES (678, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":8,\"content\":\"<p>混合双打速度快SHFLKSNFJKNKmWNDSAKNL.CN IWDJ\\t舒服舒服水电费多福多寿放大说法是多少递四方速递发放干哈撒额下达发达VVC发瓜娃儿违法的更大更啊都发给</p>\",\"createTime\":\"2025-04-01 09:58:35\",\"img\":\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/01/67eb482ad14181298a8c3b63.jpeg\",\"newsId\":29,\"params\":{},\"status\":2,\"title\":\"这是一条国际新闻\",\"updateTime\":\"2025-04-08 10:26:06\",\"userId\":2}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 10:26:06', 15);
INSERT INTO `sys_oper_log` VALUES (679, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":8,\"content\":\"<p style=\\\"text-align: left;\\\"> &nbsp; &nbsp; &nbsp;4月6日电 综合美媒报道，当地时间5日，美国多地举行名为“放手”(Hands Off)的抗议活动，以表达对特朗普政府政策以及“政府效率部”负责人马斯克的反对。</p><p style=\\\"text-align: left;\\\">　　据美国有线电视新闻网(CNN)报道，抗议活动的组织方表示，在美国全国各地的州议会大厦、联邦大楼、公园和市政厅等地，举行了抗议活动，以此表达对美国政府“解雇联邦工作人员、关闭社会保障局外地办事处、驱逐移民、以及削减健康项目资金等举动的不满”。</p><p style=\\\"text-align: left;\\\">　　据《华尔街日报》报道，不少抗议者们抱怨鸡蛋价格上涨，担心社会保障被削减。</p><p style=\\\"text-align: left;\\\">　　报道指出，在当天的抗议活动中，还“充斥着对关税和市场崩盘的愤怒”。</p><p style=\\\"text-align: left;\\\">　　芝加哥民众亚娜在标语上写着，“特朗普在打高尔夫球，而股市在暴跌”。亚娜补充说，她担心关税会导致汽车价格变得更昂贵。</p><p style=\\\"text-align: left;\\\">　　据报道，当被问及抗议活动时，白宫在一份声明中表示，“特朗普总统的立场很明确：他将永远保护符合条件的受益人的社会保障、医疗保险和医疗补助。”</p><p style=\\\"text-align: left;\\\">　　白宫声明还称，“民主党的立场是向非法外国人提供社会保障、医疗补助和医疗保险福利，而这将使这些计划破产并压垮美国老年人。”</p><p><br></p>\",\"createBy\":\"weiyan\",\"createTime\":\"2025-04-08 10:29:05\",\"img\":\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/08/67f489ecd141913ee23fa844.jpg\",\"newsId\":34,\"params\":{},\"status\":1,\"title\":\"美媒：美国举行抗议活动 “充斥着对关税和市场崩盘的愤怒”\",\"updateTime\":\"2025-04-08 10:29:12\",\"userId\":11}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 10:29:12', 7);
INSERT INTO `sys_oper_log` VALUES (680, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":8,\"content\":\"<p>混合双打速度快SHFLKSNFJKNKmWNDSAKNL.CN IWDJ\\t舒服舒服水电费多福多寿放大说法是多少递四方速递发放干哈撒额下达发达VVC发瓜娃儿违法的更大更啊都发给</p>\",\"createTime\":\"2025-04-01 09:58:35\",\"img\":\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/01/67eb482ad14181298a8c3b63.jpeg\",\"newsId\":29,\"params\":{},\"status\":0,\"title\":\"这是一条国际新闻\",\"updateTime\":\"2025-04-08 10:35:06\",\"userId\":2}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 10:35:06', 7);
INSERT INTO `sys_oper_log` VALUES (681, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":4,\"content\":\"<h1 style=\\\"text-align: justify;\\\">引言</h1><p style=\\\"text-align: justify;\\\">从匈奴到女真，从契丹到突厥，名字一个比一个霸气，结果到了现代，听着都像是“胡人串场”。</p><p style=\\\"text-align: justify;\\\"><strong>问题来了：这些名字，到底是民族、政权，还是一段历史的“标签”？今天咱们就来好好捋捋。</strong></p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/a99a284c00404951b1277f3e545413c1~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744684932&amp;x-signature=DE1wkxxE5bx8y6CYx0%2BN6yKQFAY%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><h1 style=\\\"text-align: justify;\\\">打从秦朝开始，草原上这事儿就没闲过</h1><p style=\\\"text-align: justify;\\\">公元前215年，秦始皇命蒙恬出兵三十万北击匈奴，自此中原与草原正式开撕。匈奴这支部落联盟，活跃于阴山一带，南下抢劫成瘾，骚扰边地百姓，秦朝为了保住河套地区，只得构筑长城。</p><p style=\\\"text-align: justify;\\\"><strong>汉朝初年，匈奴已发展成马背上的帝国，冒顿单于坐镇漠北，公元前200年，在平城围困刘邦，气得吕雉赶紧送人质求和。</strong></p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/cb73907b04f0483694e98ee9cef2382f~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744684932&amp;x-signature=Df1qIaV95RYUpTepFEE52rfIA80%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">公元前127年，汉武帝出手，派卫青出击，斩获甚多，直捣龙城；公元前119年，霍去病奔袭漠北两千里，歼敌七万，打进了狼居胥山。匈奴元气大伤，不得不迁往西域。</p><p style=\\\"text-align: justify;\\\"><strong>东汉时分裂成南北两部，南匈奴归附汉朝，被安置在并州一带，逐渐汉化。北匈奴则远走中亚，最终在草原上消失身影。</strong></p><p style=\\\"text-align: justify;\\\">他们留下的，不只是战争记录，还在突厥、柔然的身上继续延续。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/fd86279202524b6fbd969810ae6d8391~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744684932&amp;x-signature=wJ4H2Q54xezRkLMY92%2FtNxbAHUo%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><h1 style=\\\"text-align: justify;\\\">契丹八部不是神话，是打出来的名堂</h1><p style=\\\"text-align: justify;\\\">契丹的来头不小，东胡之后，鲜卑分裂，形成契丹等多个部族。三世纪后', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 10:43:32', 9);
INSERT INTO `sys_oper_log` VALUES (682, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":1,\"content\":\"<p>说难听点，中国一个重装合成旅的战斗力远超许多国家，完全不在一个量级上。以色列陆军现役约13万人，坦克3000辆、火炮7000门，看似规模不小，但细究之下，其36个旅中仅有3个装甲旅、3个机械化步兵旅和1个伞兵旅算得上齐装满员，其余多为“骨架部队”。反观中国的重装合成旅，各旅配备99A主战坦克100 - 112辆、PLZ - 05自行榴弹炮24门、PHZ - 11模块化火箭炮18门，其火力密度堪称“全球之最”。这种差距并非偶然，以色列虽在中东战争中以少胜多，但其地面部队的短板早已暴露：2023年加沙冲突中，多辆“梅卡瓦”坦克被击毁，“纳梅尔”步兵战车被缴获，甚至“铁穹”防空系统也因饱和攻击失效。中国重装合成旅的实战化训练早已常态化，2018年中俄联合军演，中国一个合成营仅40分钟便“全歼”俄军机步团，彰显出“发现即摧毁”的碾压性战力。技术代差更是难以逾越的鸿沟，以色列虽拥有“梅卡瓦”坦克，但其120毫米滑膛炮的穿甲能力仅能击穿600毫米均质钢装甲，中国99A坦克的125毫米滑膛炮能穿透1000毫米装甲，并且装备了主动防护系统与信息化火控系统。更不必说中国重装合成旅的炮兵营，装备着27门122毫米榴弹炮、9门122毫米火箭炮以及24门120毫米迫榴炮，这般火力配置，以色列陆军只能望尘莫及。如果说以色列地面部队是“中东小霸王”，那么中国重装合成旅就是“钢铁洪流”，以色列的“梅卡瓦”坦克或许能在巷战中灵活机动，但面对中国重装合成旅的“陆战钢铁洪流”，恐怕连招架之力都难有。说句实在话，以色列地面部队和中国重装合成旅根本不在一个量级上，以色列的“梅卡瓦”坦克再厉害，能扛得住中国99A的穿甲弹吗？以色列的“铁穹”防空系统再牛，能拦截中国东风快递的“点穴”打击吗？更不必说中国重装合成旅的信息化作战能力了，在北斗卫星系统与数字化指挥链的加持下，其战场态势感知能力远超以色列。有人可能会说，以色列有美国撑腰，有先进的空中力量，但现代战争是体系对抗，不是单一兵种的较量，中国重装合成旅背后，是完整的联合作战体系，是东风快递、歼-20、055大驱的强力支援。以色列再强，也不过是中东地区的一个“小霸王”，而中国重装合成旅，代表的是全球顶尖的陆军战力。所以说以色列地面部队和中国重装合成旅的对比，就像拿一辆摩托车和一辆坦克比速度，根本没资格放在一起比较，中国一个重装合成旅，推平大多数国家还真不是吹牛，毕竟在绝对实力面前，任何技巧都是徒劳。素材来自网络，如有侵权请联系删改。</p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-ezhpy3drpa/3ede09a44d124cdcafe04ca4b6830367~tplv-obj:654:411.image?_iz=97245&amp;bid=15&amp;from=post&amp;gid=1828723813458947&amp;lk3s=06827d14&amp;x-expires=1751846400&amp;x-signature=YKt0MRKYyQJ2KR8CljxxLwdGW0Q%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p>\",\"createBy\":\"weiyan\",\"createTime\":\"2025-04-08 10:49:37\",\"img\":\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/08/67f48ebed141913ee23fa848.png\",\"newsId\":36,\"params\":{},\"status\":1,\"title\":\"以色列地面部队相当于中国几个重型合成旅？\",\"updateTime\":\"2025-04-08 10:49:48\",\"userId\":11}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 10:49:48', 7);
INSERT INTO `sys_oper_log` VALUES (683, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":2,\"content\":\"<p>“我可以是日本的，但台湾必须是中国的！”2024年8月7日，据媒体报道。在奥运会间歇，张本智和接受采访时，因“口误”引起了全球热搜！</p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-ezhpy3drpa/ef19591a72b64cac8aa952df89edc1b2~tplv-obj:818:554.image?_iz=97245&amp;bid=15&amp;from=post&amp;gid=1828559392435403&amp;lk3s=06827d14&amp;x-expires=1751846400&amp;x-signature=E%2B3ioKBbtxrbK4qclbQkd1vzjUE%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"width: 525.60px;height: 355.95px;\\\">张本智和的名字可能很多人都知晓，作为一个出生于2003年的乒乓球运动员，其祖籍是中国四川省，但是在2014年的时候却选择加入了日本国籍，之后代表日本参加了很多重要的国际赛事。而张本智和之所以会备受外界评判，最主要的原因是因为其祖籍的缘故。很多人认为张本志和的祖籍是中国四川，那么他就是中国人，但是作为中国人却加入了日本的国籍，那么就是一个叛徒。<img src=\\\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/08/67f490c3d141913ee23fa84a.png\\\" alt=\\\"1c11cf85606d4035961bf45b7966a5ef~tplv-obj_831_413.png\\\" data-href=\\\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/08/67f490c3d141913ee23fa84a.png\\\" style=\\\"width: 525.60px;height: 261.21px;\\\">可就是这样一个备受外界争论的运动员，在奥运会间隙接受记者采访，被询问到下场对手是谁时，他脱口而出的“台北队”刚说到一半，就立马更改成了“中国台北队”。也正因为他的这一反应，迅速引起了全球的广泛关注。近年来因为台海问题，我国一直备受广泛的关注。不管是从历史的角度去看，还是从未来的走向去看，台湾是属于中国的一片领土，这是一个不可被否认的事实。但是台湾内部的台独分子，却一直试图挑起纷争，想让台湾彻底独立。<img src=\\\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/08/67f490d4d141913ee23fa84b.png\\\" alt=\\\"e544444625ad41ab9d16339ebea28d5b~tplv-obj_554_368.png\\\" data-href=\\\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/08/67f490d4d141913ee23fa84b.png\\\" style=\\\"width: 546.00px;height: 362.68px;\\\">所以张本智和的这一口误，迅速引起了广泛关注。有人认为张本智和虽然加入了日本，但是在他的内心台北仍旧是属于中国的。其实对于运动员，我们应该以客观的角度去看，毕竟对于运动员来说，发展才是最为关键的东西。也有很多运动员为了更好的发展，选择加入其他国籍。那么对于张本智和的这一“口误”，你如何看待？欢迎评论区留言，你的看法我们一起讨论，等一下。</p><p><br></p>\",\"createBy\":\"weiyan\",\"createTime\":\"2025-04-08 10:59:06\",\"img\":\"https://blue-bishe.oss-cn-hangzhou.aliyuncs.com/newstrc-images/2025/04/08/67f490f8d141913ee23fa84c.jpg\",\"newsId\":37,\"params\":{},\"status\":1,\"title\":\"张本智和：“我可以是日本的，但台湾必须是中国的！”\",\"updateTime\":\"2025-04-08 10:59:18\",\"userId\":11}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 10:59:18', 8);
INSERT INTO `sys_oper_log` VALUES (684, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<p style=\\\"text-align: justify;\\\">1、烤柠檬鸡腿</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/86661e7ae8c14234a40bcd5ab8a16cf6~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686610&amp;x-signature=Yhx5k5nn9HAR2sSaQ02lIXRlltY%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/f1db9d27ba774e7ca2d2099be39cefeb~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686610&amp;x-signature=hCwhQqQDztvZ1Pp2Mt1UC65QaH4%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/4791d62663614ae9b17064020d8f0d15~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686610&amp;x-signature=Xr3TUjvD51QaYHue1KaGCfrZps4%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">2、烤鸡肉串串</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/eb17018e930f430894db233d8ea55f04~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686610&amp;x-signature=YjcJWeONMxcR7%2Fp0cXuHa%2FaERPE%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/ef79a638d2b24659b5d0bd089b507094~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686610&amp;x-signature=vgO9w9hCZJA5M3E10f0VCuOhLFE%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/559655521b914cc7aa7c06ed32fdde5a~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686610&amp;x-signature=YsxXOGdmd5H2w3xwZfco4VN1weo%3D\\\" alt=\\\"\\\" data-hr', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:11:18', 9);
INSERT INTO `sys_oper_log` VALUES (685, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<p style=\\\"text-align: justify;\\\">虽然说现在的美食特别多，随便走在哪条街道上都能看到各种各样的美食店，不过自助餐仍然是大部分人的选择，尤其是小孩子更喜欢吃自助餐。</p><p style=\\\"text-align: justify;\\\">因为自助餐里面的食品种类非常多，它就可以满足不同人群的不同需求，不过自助餐的价格可不便宜，随便一家店就是100多一位，稍微好一点的店就是两三百一位，一家人去吃的话，怎么样都要花上大几百块钱。所以在吃自助餐时，我们在心里往往就有个小算盘：一定要吃回本，这好像也成了吃自助餐的一大乐趣。那该如何吃回本呢？接下来就来跟大家分享自助餐里的5种隐形贵菜，老板生怕你多拿！</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/3786c49e96054e8ea24c60863b8f2b83~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686280&amp;x-signature=lfwbrnlfUI0JcAYh53ESaBiM5nI%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>一、新鲜海鲜</strong></p><p style=\\\"text-align: justify;\\\">各种海鲜就是自助餐的一大特色了，有些自助餐就是以海鲜为主，它的价格还会更贵一些。面对自助餐里各种各样的海鲜，很多人都只关注那些冷冻或者腌制之类的，但其实鲜活的海鲜才是重头戏，鲜活海鲜它的品质高，口感和营养也更好些，相比于那些冷冻的海鲜，价格也要贵上一些，比如活虾、螃蟹、生蚝之类的。</p><p style=\\\"text-align: justify;\\\">像活虾，市场上都要四、五十一斤；生蚝的话，我们在夜宵摊上烤个新鲜的生蚝都要7、8块，甚至十几块，而螃蟹的价格就更贵了。这些鲜活的海鲜，随便吃上几个，就要回一大半的本了。所以，我们来到自助餐厅时，首先就要记得到海鲜区看看，要是看到螃蟹和鲜活大虾，就赶紧多拿一些，不然等会儿就没了。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/f7c475d6ac764c2788717d299173798f~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686280&amp;x-signature=aLe4tOfFrvjnpcXAIAd3b1MOSbU%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>二、鲜切肉类。</strong></p><p style=\\\"text-align: justify;\\\">自助餐中提供的肉类，就有腌制肉和新鲜的肉片，很多朋友会选择腌制好的肉，因为已经腌制入味了，吃起来的口感就会更好。但其实，这些腌肉大多都是使用一些边角料或者不新鲜的食材，然后加入大量的调料腌制的，它的新鲜度差，就更别提什么营养了，好吃也无非是因为它使用的调料多。而那些新鲜的肉类，比如牛肉、羊肉之类的，这些才是精品，不仅品质高、价格高，而且营养价值也更好。因此，在吃自助餐的时候，不妨看看那些鲜切的肉类，它们才能让我们吃得过瘾、吃的放心。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/93f3e7d0d3e04d2cab15f0fd5baa868e~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-ex', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:11:24', 12);
INSERT INTO `sys_oper_log` VALUES (686, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<p style=\\\"text-align: justify;\\\"><strong>【鸡蛋打卤面】</strong></p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/5ac2ea8f69b741e6b75738732c2b1e6e~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686204&amp;x-signature=BStR3e5GpG1m%2FWvcITy0RoYwEmY%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><strong>制作步骤：</strong></p><p style=\\\"text-align: justify;\\\">1.首先把买回来的辣椒清洗干净，然后再改刀切成大小均匀的小丁。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/6f4c880c55014db1b1e106846c838105~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686204&amp;x-signature=a8J%2Bs3r9d4O9YPa6nw7jBpRCQCA%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">2.接下来调个酱汁，找一个空碗，碗中加入2勺生抽、1勺蚝油、1勺鸡精、2勺黄豆酱、适量白糖提鲜，少许老抽上色，然后倒入半碗水淀粉。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/53f54d0bf15044728148054e196a8185~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686204&amp;x-signature=PWgvBQd0CDBgcbB%2Fxt2%2FcSVrXhs%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">3.再把调制好的酱汁搅拌均匀。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/f0d107b903f44c1bb14e20879a5e8aff~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686204&amp;x-signature=K%2FJUbfdhI7BXBdsCqv2CpY4cbzM%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">4.起锅烧油，油热倒入3个打好的鸡蛋液，炒熟炒散盛出来装盘备用。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/65fa643db00349aea07afa14d7f39f87~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=artic', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:11:31', 8);
INSERT INTO `sys_oper_log` VALUES (687, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<p style=\\\"text-align: justify;\\\">一、<strong>沙瓤西红柿：舌尖上的“红宝石”，如今只剩酸涩</strong></p><p style=\\\"text-align: justify;\\\">在80后的童年里，沙瓤西红柿是夏日最甜蜜的期待。它的皮薄如蝉翼，轻轻一咬，鲜红的果肉裹着沙沙的果瓤，汁水瞬间充盈口腔，甜中带酸的风味让人停不下来。老辈人常说：“那时的西红柿不用糖拌，空口能吃一盘！” 然而，如今的西红柿硬得像石头，酸涩难以下咽。沙瓤品种因皮薄易破、不耐储运，逐渐被追求高产耐运输的硬果品种取代。即便偶见市面，也因长途运输损耗大，价格高企，成了“稀罕物”。 <strong>消失的真相</strong>：现代农业的规模化需求，让“口感”输给了“效率”。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/a0505205a4aa42e6ae690feb0d651ff3~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686459&amp;x-signature=rdrGjZqIEJx0oiqPIara71G5eNY%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p><br></p><p><br></p><p style=\\\"text-align: justify;\\\">二、<strong>亭林雪瓜：百年名瓜的“十道棱沟”，敌不过市场洪流</strong></p><p style=\\\"text-align: justify;\\\">上海金山的亭林雪瓜，曾以“十道棱沟”的精致外形和松脆香甜的口感闻名。它的皮薄到可以连皮带肉一起吃，瓜肉如婴儿肌肤般细腻，汁水清甜如蜜。2019年，它虽获国家地理标志认证，却难逃种植面积锐减的命运。 老瓜农回忆：“以前家家种雪瓜，现在年轻人嫌麻烦，都改种普通甜瓜了。”传统种植需精细管理，一年收六七茬，但亩产低、成本高，逐渐被高产品种挤出市场。 <strong>最后的倔强</strong>：仅存的种植户坚持用古法栽培，只为留住“老上海的味道”。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/7b358209283149b7a74c8bc41104f27a~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686459&amp;x-signature=9NyoW%2Bx5SMI1ngyHOxYhiO56xcs%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p><br></p><p><br></p><p style=\\\"text-align: justify;\\\">三、<strong>榅桲（木梨）：4000年历史的“金苹果”，败给时代口味</strong></p><p style=\\\"text-align: justify;\\\">新疆的榅桲，古埃及人眼中的“金苹果”，果香似菠萝，入口微涩，蒸煮后软糯香甜。这种果皮带绒毛的古老水果，曾是丝绸之路上的珍品，如今却因产量稀少、口感偏硬，成了超市里的“稀客”。 年轻人嫌它“吃法麻烦”，商家抱怨“运输易损”，连新疆本地人也感叹：“小时候满街都是，现在想买得碰运气。” <strong>苦涩的现实</strong>：传统风味与现代快节奏消费的碰撞，让历史输给了便利。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/55c2877eb4304fa2b923f9f8dc149747~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:11:36', 12);
INSERT INTO `sys_oper_log` VALUES (688, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<h1 style=\\\"text-align: justify;\\\"><span class=\\\"ql-size-small\\\">在日常生活中，很多人都忽视了身边一些天然的“黄金水果”，它们不仅美味可口，还有着极高的营养价值，特别是在养肝护肝方面有着不可忽视的作用。中医讲究“食疗”，认为肝脏是人体的重要器官，肝气不畅或肝脏功能不佳，容易导致身体出现各种问题。而这些隐藏在我们身边的“黄金水果”，不仅可以帮助我们排毒养肝，还能增强体质，改善整体健康状况。今天，就让我们来了解三种非常适合养肝的水果，以及如何搭配它们做成滋补的汤品和美味的饮品。</span></h1><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/ec4379d26b9f41e8a0cf7b64b53f20a5~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686892&amp;x-signature=aPiKEtd%2F5KJqCh2uB9%2BkSQ2oV5g%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-indent: 2em; text-align: justify;\\\"><strong>一、无花果玉竹莲子汤</strong></p><p style=\\\"text-indent: 2em; text-align: justify;\\\">所需材料：干无花果：6颗；干玉竹：20克；莲子（干）：30克；枸杞：适量（可选）；冰糖：适量（根据口味调整）；清水：适量</p><p style=\\\"text-indent: 2em; text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/2eda5f10b0ae43b18490c929698f2bb8~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686892&amp;x-signature=fT1FuGM5B8vQ91Vxa8MeliPl3Qs%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-indent: 2em; text-align: justify;\\\">步骤：</p><p style=\\\"text-indent: 2em; text-align: justify;\\\">1. 准备食材：先将干无花果、干玉竹、干莲子分别清洗干净，去除杂质。无花果可以轻轻剪去蒂头。</p><p style=\\\"text-indent: 2em; text-align: justify;\\\">2. 莲子浸泡：将干莲子放入清水中浸泡2小时，让莲子变软。泡软后的莲子可以去掉莲芯，这样汤品更加清香，不会有苦味。</p><p style=\\\"text-indent: 2em; text-align: justify;\\\">3. 玉竹处理：玉竹因为质地较硬，建议用清水冲洗后，用温水浸泡20分钟，软化后备用。</p><p style=\\\"text-indent: 2em; text-align: justify;\\\">4. 准备炖盅：取一个炖盅，将浸泡好的莲子、玉竹、无花果放入炖盅中。根据个人口味，加入适量的枸杞。</p><p style=\\\"text-indent: 2em; text-align: justify;\\\">5. 加水：向炖盅中加入适量的清水，水量需覆盖食材约2-3厘米。</p><p style=\\\"text-indent: 2em; text-align: justify;\\\">6. 炖煮：将炖盅放入蒸锅中，蒸煮1-1.5小时，火候保持在中小火。这样可以使食材的营养成分充分释放到汤中。</p><p style=\\\"text-indent: 2em; text-align: justify;\\\">7. 调味：炖煮完成后，取出汤，加入适量的冰糖调味，搅拌均匀，继续小火煮5-10分钟，直到冰糖完全融化。</p><p style=\\\"text-ind', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:15:49', 8);
INSERT INTO `sys_oper_log` VALUES (689, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<p style=\\\"text-align: justify;\\\"><span style=\\\"color: rgb(240, 65, 66);\\\">开启健康新一天：早餐必备的 4 种“脾胃呵护宝”</span></p><p style=\\\"text-align: justify;\\\">早餐是一天中最重要的一餐，吃好了，一整天都元气满满；吃不对，脾胃受苦，身体跟着遭罪。要是您能在早餐桌上常摆上这 4 种食物，坚持吃下来，脾胃越来越强壮，健康自然就来“敲门”啦。接下来就给您唠唠这几样好东西，顺带奉上美味又简单的食谱。</p><p style=\\\"text-align: justify;\\\"><br></p><p style=\\\"text-align: justify;\\\"><strong>一、山药</strong>——健脾益胃“白胖子”</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/6a40d0f3153341d3b9b1968da9295747~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686819&amp;x-signature=PKFw%2FlB%2F04ag91Yd4IDLWDQ3y0Q%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">山药是调理脾胃的“明星食材”。它含有丰富的淀粉酶、多酚氧化酶等物质，能促进脾胃消化吸收，不管是脾胃虚弱的老人孩子，还是三餐不规律的上班族，吃它都益处多多。</p><p style=\\\"text-align: justify;\\\"><br></p><p style=\\\"text-align: justify;\\\"><strong>山药红枣粥</strong>：</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/f3bfc61b3bc2419b83665b453ed44be3~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686819&amp;x-signature=ZV25HGGyJlZx%2FdkmX%2BrevyttmF4%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">1、把山药去皮洗净，切成小段，红枣去核洗净，大米淘洗干净。</p><p style=\\\"text-align: justify;\\\">2、锅中加水，放入大米，大火煮开后转小火煮 10 分钟，加入山药段和红枣，继续小火慢熬 20 分钟，直至山药煮得软糯、粥变得浓稠，放入冰糖调味，搅拌均匀即可出锅。这粥口感软糯香甜，每天早上来一碗，暖呼呼地下肚，脾胃就像被轻柔地按摩了一样，舒坦极了。</p><p style=\\\"text-align: justify;\\\"><br></p><p style=\\\"text-align: justify;\\\"><strong>二、南瓜—</strong>—滋养脾胃“金疙瘩”</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/d307af1b5ccf4b7eaadca52f282e6cb4~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686819&amp;x-signature=lr6r3GL%2B24DqalhVdyfQR8Pr%2Bfw%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: au', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:15:56', 8);
INSERT INTO `sys_oper_log` VALUES (690, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<h1 style=\\\"text-align: justify;\\\">油焖大虾</h1><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/8964b567e6c8447da06fdd455cc5f92c~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687049&amp;x-signature=ch4Dm3Owe1nTQNm2kSsRpMGexQI%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">食材：虾、葱、姜、蒜</p><p style=\\\"text-align: justify;\\\">做法：</p><p style=\\\"text-align: justify;\\\">1、调酱汁：1勺料酒、2勺生抽、半勺老抽、1勺香醋、1勺蚝油、1勺番茄酱、半勺白糖，适量凉水拌匀</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/6ca05d8a661241ea9b16f4f86f4e088a~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687049&amp;x-signature=1GwJ%2FiUnPLi7MEkT8CGwHRO1H%2Bw%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">2、虾洗净去虾线虾枪虾须</p><p style=\\\"text-align: justify;\\\">3、热油炒香葱姜蒜末</p><p style=\\\"text-align: justify;\\\">4、倒入虾翻炒至变色</p><p style=\\\"text-align: justify;\\\">5、倒入调好的酱汁</p><p style=\\\"text-align: justify;\\\">6、翻炒至浓稠收汁，撒上葱花</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/de9b966a2664430883ff852d5cde770d~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687049&amp;x-signature=DoCRxICszLWtabdcl2jHZDxGDpo%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/e9429e8138b444e995db75affeea4ddc~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687049&amp;x-signature=GSeKg6AdCOzyNeH2b5hJLuESGGs%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/7b6524f3231e4a22a76f8eb23fa01b5b~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expire', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:19:32', 8);
INSERT INTO `sys_oper_log` VALUES (691, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":7,\"content\":\"<p style=\\\"text-align: justify;\\\">不知道有没有小伙伴发现，虽然各家的旗舰手机都已经上市了，但似乎还差了一档，那就是Ultra级别的旗舰机型，现在只有小米15 Ultra在售，其他品牌呢？现在vivo也官宣了，自家的vivo X200 Ultra定档4月21日。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/d1b45606d171462fa28dbef05d95b4e9~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687543&amp;x-signature=SAyOwXKaiGQ%2FsoTNV3iDDqI7UFo%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">现在已经有一些关于这款手机的关键信息披露了，包括骁龙8 Elite芯片、6.82英寸京东方2K屏幕、6000mAh+级别的超大电池以及90W快充、单点超声波指纹，加上IP68、IP69防尘防水，以及顶配版支持北斗消息等。</p><p style=\\\"text-align: justify;\\\">不过，作为顶级旗舰，这些参数看起来稍微显得常规了，其实这次vivo旗舰手机变化挺大，包括手机的宣传都在对标微单产品。只是，vivo这次真是有点让人担心步子大了会不会扯到蛋。为什么这么说呢？咱们先全面看一下产品特性。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/a431da49ccb14c9fbdd2f71f2f213284~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687543&amp;x-signature=SkZSxLsA9KQ93lkULQjk69kIBAQ%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">首先外观方面，vivo X200 Ultra采用了等深微曲屏方案，摄像头模组毫无疑问还一个大圆盘。外观设计方面，这次曝光的则是银色机身的型号。机身这个条纹设计是不是有点眼熟？好像在机场或者高铁站见过？</p><p style=\\\"text-align: justify;\\\">此前传闻vivo和著名行李箱品牌RIMOWA合作，恰好和蔡司一样又是一家德国公司。虽然现在官方没有确认消息，但不得不说手机的设计确实是有RIMOWA经典产品的味道，而且两家产品有一个共同特色就是贵。不对，应该是三家，毕竟蔡司的也挺贵。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/4807dd690cbf452a908b171c73bdd476~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687543&amp;x-signature=pwi5Z05nil%2BdHHRmsVG3Wet0g1o%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">接下来就该说说和拍照相关了。首先，vivo X200 Ultra也在侧边增加了一个按键。虽然苹果iPhone16系列侧键体验不佳被诟病，但该学还是要学。苹果没做好，难道别家还做不好吗？</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:26:50', 9);
INSERT INTO `sys_oper_log` VALUES (692, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":6,\"content\":\"<p style=\\\"text-align: justify;\\\"><span style=\\\"color: rgb(0, 0, 0);\\\">在中国旅游圈里有个不成文的默契——有些地方有钱也进不去，比如河南洛阳的老君山。这座海拔2217米的山峰，顶着“天下无双圣境”的称号，却对外国人紧闭大门。甭管你是华尔街大佬还是哈佛教授，只要不是中国公民，连景区售票处都摸不着边。今天咱们就扒一扒，这座“中国专属”的仙山到底藏着什么秘密。</span></p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/cc398c86c19644f0bfe97fbcb0dd854c~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687920&amp;x-signature=BYgia8yLswdWy18GmHPtS3slC88%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><span style=\\\"color: rgb(0, 0, 0);\\\">老君山的“排外”规矩，最早要从八十年前说起。1944年日本鬼子打到河南，冲着山顶的老君庙连轰13发炮弹，结果愣是没炸响一颗。当地人坚信这是太上老君显灵，这事儿还被记进了县志。直到现在，栾川县还挂着“军事管理区”的牌子，山里头藏着啥咱老百姓不知道，但南方人进去都得办《边境通行证》。</span></p><p style=\\\"text-align: justify;\\\"><span style=\\\"color: rgb(0, 0, 0);\\\">去年有个美国地质考察团，带着高端设备想来研究山体结构，结果在县里就被拦下了。景区门口的中英文警示牌写得明明白白：“外国人未经批准不得入内”，连无人机飞过都要报备。有网友调侃：“这山看着仙气飘飘，怕不是藏着东风快递的发射井？”</span></p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/e233c9522cac4e878df0acd38f588d32~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687920&amp;x-signature=%2F2Il8RhDLJHlL3vZjMiqAo01Alw%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\"><span style=\\\"color: rgb(0, 0, 0);\\\">老君山还有个外号叫“中药界的诺亚方舟”。整座山八百多种草药扎堆生长，光是国家级的保护植物就有102种。《本草纲目》里记载的七叶一枝花、伏牛山石斛这些绝版药材，在这儿就跟野草似的往外冒。</span></p><p style=\\\"text-align: justify;\\\"><span style=\\\"color: rgb(0, 0, 0);\\\">景区巡逻队最头疼的不是游客乱扔垃圾，而是防着本地人挖草药。前年有个采药大爷偷偷刨了棵紫斑牡丹，结果被判了三年——那玩意儿在黑市上能换辆宝马。更绝的是，山顶的土壤样本都被军方管控，外国科研机构出价千万也买不到一克。</span></p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/9bbf6db21e444c70a52bbb005797cf38~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744687920&amp;x-signature=kWa1YgaXDHgwgNrKui', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:33:27', 8);
INSERT INTO `sys_oper_log` VALUES (693, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":6,\"content\":\"<h1 style=\\\"text-align: justify;\\\">1、安徽黄山</h1><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/ac7a48a779e64612a3c375c00095bb40~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744688232&amp;x-signature=bfKsFKtYwJF6HuONIem1q4Bo1wM%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">黄山以“奇松、怪石、云海、温泉、冬雪”五绝闻名，是世界文化与自然双遗产。春秋季气候温和，云海频现，奇松怪石与光影交织，宛若水墨画。</p><p style=\\\"text-align: justify;\\\"><strong>最佳时节：春秋季（3-5月、9-11月）</strong></p><h1 style=\\\"text-align: justify;\\\"> 2、吉林长白山</h1><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/d8d4614b92d24ed69e5728081055c878~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744688232&amp;x-signature=To4%2BIEzuwgK%2BAxZ%2FfzMBH5GrwQo%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">冬季的长白山是雪域天堂，可体验雾凇漂流、火山温泉和粉雪滑雪。天池被白雪覆盖，雾凇景观如仙境，运气好还能看到冰封天池的震撼。</p><p style=\\\"text-align: justify;\\\"><strong>最佳时节：冬季（12月-次年2月）</strong></p><h1 style=\\\"text-align: justify;\\\"> 3、四川九寨沟</h1><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/71704321d3cc4cf3856f7541396ab649~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744688232&amp;x-signature=yUmVM%2F6SfUPMjUfXtEF6wUw5Ex8%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">秋天的九寨沟层林尽染，五彩斑斓的湖泊与瀑布交相辉映，被誉为“童话世界”。此时水量充沛，红叶与碧水形成极致对比。</p><p style=\\\"text-align: justify;\\\"><strong>最佳时节：秋季（10月下旬-11月中旬）</strong></p><h1 style=\\\"text-align: justify;\\\">4、湖南张家界</h1><p><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/68680429a0d14565a5bc78302121593d~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744688232&amp;x-signature=3CrEMQ7N3CtGGt83t%2BqSX%2BEMlyI%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:38:07', 11);
INSERT INTO `sys_oper_log` VALUES (694, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":4,\"content\":\"<p style=\\\"text-align: justify;\\\"><u><em><strong>一、为何千年未启？——地宫之谜的永恒诱惑</strong></em></u></p><p style=\\\"text-align: justify;\\\">司马迁在《史记》中仅用百余字描述秦始皇陵：「穿三泉，下铜而致椁，宫观百官奇器珍怪徙臧满之。以水银为百川江河大海，机相灌输。」这座深埋骊山脚下两千年的地下帝国，究竟藏着多少惊世秘密？当1974年兵马俑偶然现世时，世界第一次窥见了秦代文明的冰山一角，但真正的主陵地宫至今仍被重重谜团笼罩。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/3fb6fb44862c4e099f42795a3c15ea6b~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744688394&amp;x-signature=xdBp1BrzBSM11F7KN1B8wCJ6k%2F0%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p style=\\\"text-align: center;\\\">图片仅供参考</p><p style=\\\"text-align: left;\\\">---</p><p style=\\\"text-align: justify;\\\"><u><em><strong>二、史书记载中的“黑科技”</strong></em></u></p><p style=\\\"text-align: justify;\\\"><em><strong>1. 水银江河之谜</strong></em></p><p style=\\\"text-align: justify;\\\">现代探测证实，地宫上方土壤汞含量异常，印证了司马迁的记载。以秦代技术如何实现水银循环系统？这究竟是防腐设计，还是对「天文地理」的象征性模拟？</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/b7bce98c619744c498ccda80650a0028~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744688394&amp;x-signature=QPNb49vf2oTOUTBEbI31%2FANWdN4%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p style=\\\"text-align: center;\\\">图片仅供参考</p><p style=\\\"text-align: justify;\\\">（科学推测：利用秦岭汞矿与温差驱动的流体力学）</p><p style=\\\"text-align: justify;\\\"><em><strong>2. 机关暗器之谜</strong></em></p><p style=\\\"text-align: justify;\\\">《汉书》记载「机弩矢，有所穿近者辄射之」，传说中的「流沙层」「悬剑阵」是否真实存在？考古学家在陪葬坑中发现青铜齿轮与精密榫卯结构，暗示着超越时代的机械装置。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/9cd5f95923704fbe8b567ca80ab0d9b3~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744688394&amp;x-signature=cZTbMKScIiITo56zcbKWfV2nTt0%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p style=\\\"text-align: center;\\\">图片仅供参考</p><p', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-08 11:40:46', 8);
INSERT INTO `sys_oper_log` VALUES (695, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<p style=\\\"text-align: justify;\\\">一、<strong>沙瓤西红柿：舌尖上的“红宝石”，如今只剩酸涩</strong></p><p style=\\\"text-align: justify;\\\">在80后的童年里，沙瓤西红柿是夏日最甜蜜的期待。它的皮薄如蝉翼，轻轻一咬，鲜红的果肉裹着沙沙的果瓤，汁水瞬间充盈口腔，甜中带酸的风味让人停不下来。老辈人常说：“那时的西红柿不用糖拌，空口能吃一盘！” 然而，如今的西红柿硬得像石头，酸涩难以下咽。沙瓤品种因皮薄易破、不耐储运，逐渐被追求高产耐运输的硬果品种取代。即便偶见市面，也因长途运输损耗大，价格高企，成了“稀罕物”。 <strong>消失的真相</strong>：现代农业的规模化需求，让“口感”输给了“效率”。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/a0505205a4aa42e6ae690feb0d651ff3~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686459&amp;x-signature=rdrGjZqIEJx0oiqPIara71G5eNY%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p><br></p><p><br></p><p style=\\\"text-align: justify;\\\">二、<strong>亭林雪瓜：百年名瓜的“十道棱沟”，敌不过市场洪流</strong></p><p style=\\\"text-align: justify;\\\">上海金山的亭林雪瓜，曾以“十道棱沟”的精致外形和松脆香甜的口感闻名。它的皮薄到可以连皮带肉一起吃，瓜肉如婴儿肌肤般细腻，汁水清甜如蜜。2019年，它虽获国家地理标志认证，却难逃种植面积锐减的命运。 老瓜农回忆：“以前家家种雪瓜，现在年轻人嫌麻烦，都改种普通甜瓜了。”传统种植需精细管理，一年收六七茬，但亩产低、成本高，逐渐被高产品种挤出市场。 <strong>最后的倔强</strong>：仅存的种植户坚持用古法栽培，只为留住“老上海的味道”。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/7b358209283149b7a74c8bc41104f27a~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686459&amp;x-signature=9NyoW%2Bx5SMI1ngyHOxYhiO56xcs%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p><br></p><p><br></p><p style=\\\"text-align: justify;\\\">三、<strong>榅桲（木梨）：4000年历史的“金苹果”，败给时代口味</strong></p><p style=\\\"text-align: justify;\\\">新疆的榅桲，古埃及人眼中的“金苹果”，果香似菠萝，入口微涩，蒸煮后软糯香甜。这种果皮带绒毛的古老水果，曾是丝绸之路上的珍品，如今却因产量稀少、口感偏硬，成了超市里的“稀客”。 年轻人嫌它“吃法麻烦”，商家抱怨“运输易损”，连新疆本地人也感叹：“小时候满街都是，现在想买得碰运气。” <strong>苦涩的现实</strong>：传统风味与现代快节奏消费的碰撞，让历史输给了便利。</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/55c2877eb4304fa2b923f9f8dc149747~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-23 21:04:54', 20);
INSERT INTO `sys_oper_log` VALUES (696, '新闻内容', 2, 'com.newsrec.manage.controller.NewsController.edit()', 'PUT', 1, 'admin', '研发部门', '/manage/news', '127.0.0.1', '内网IP', '{\"categoryId\":3,\"content\":\"<p style=\\\"text-align: justify;\\\"><span style=\\\"color: rgb(240, 65, 66);\\\">开启健康新一天：早餐必备的 4 种“脾胃呵护宝”</span></p><p style=\\\"text-align: justify;\\\">早餐是一天中最重要的一餐，吃好了，一整天都元气满满；吃不对，脾胃受苦，身体跟着遭罪。要是您能在早餐桌上常摆上这 4 种食物，坚持吃下来，脾胃越来越强壮，健康自然就来“敲门”啦。接下来就给您唠唠这几样好东西，顺带奉上美味又简单的食谱。</p><p style=\\\"text-align: justify;\\\"><br></p><p style=\\\"text-align: justify;\\\"><strong>一、山药</strong>——健脾益胃“白胖子”</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-axegupay5k/6a40d0f3153341d3b9b1968da9295747~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686819&amp;x-signature=PKFw%2FlB%2F04ag91Yd4IDLWDQ3y0Q%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">山药是调理脾胃的“明星食材”。它含有丰富的淀粉酶、多酚氧化酶等物质，能促进脾胃消化吸收，不管是脾胃虚弱的老人孩子，还是三餐不规律的上班族，吃它都益处多多。</p><p style=\\\"text-align: justify;\\\"><br></p><p style=\\\"text-align: justify;\\\"><strong>山药红枣粥</strong>：</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/f3bfc61b3bc2419b83665b453ed44be3~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686819&amp;x-signature=ZV25HGGyJlZx%2FdkmX%2BrevyttmF4%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: auto;\\\"></p><p><br></p><p style=\\\"text-align: justify;\\\">1、把山药去皮洗净，切成小段，红枣去核洗净，大米淘洗干净。</p><p style=\\\"text-align: justify;\\\">2、锅中加水，放入大米，大火煮开后转小火煮 10 分钟，加入山药段和红枣，继续小火慢熬 20 分钟，直至山药煮得软糯、粥变得浓稠，放入冰糖调味，搅拌均匀即可出锅。这粥口感软糯香甜，每天早上来一碗，暖呼呼地下肚，脾胃就像被轻柔地按摩了一样，舒坦极了。</p><p style=\\\"text-align: justify;\\\"><br></p><p style=\\\"text-align: justify;\\\"><strong>二、南瓜—</strong>—滋养脾胃“金疙瘩”</p><p style=\\\"text-align: justify;\\\"><img src=\\\"https://p3-sign.toutiaoimg.com/tos-cn-i-6w9my0ksvp/d307af1b5ccf4b7eaadca52f282e6cb4~tplv-tt-origin-web:gif.jpeg?_iz=58558&amp;from=article.pc_detail&amp;lk3s=953192f4&amp;x-expires=1744686819&amp;x-signature=lr6r3GL%2B24DqalhVdyfQR8Pr%2Bfw%3D\\\" alt=\\\"\\\" data-href=\\\"\\\" style=\\\"height: au', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-04-23 21:05:30', 11);
